    print(f"Test 4 FAILED: {e}")

# Test 5: DateTime directly in Schema (not in container)
class MySchema5(Schema):
    time = fields.DateTime()

try:
    s = MySchema5()
    print("Test 5 PASSED: DateTime directly in Schema works")
